import{_ as a,d as o,e as d,a as r,b as e,c as i,f as l}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as c,c as n,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Discord 채널 추가","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/upload/discord.md","filePath":"ko-KR/upload/discord.md","lastUpdated":1781962217000}'),p={name:"ko-KR/upload/discord.md"};function m(_,t,b,D,u,B){return c(),n("div",null,[...t[0]||(t[0]=[h('<h1 id="discord-채널-추가" tabindex="-1">Discord 채널 추가 <a class="header-anchor" href="#discord-채널-추가" aria-label="Permalink to &quot;Discord 채널 추가&quot;">​</a></h1><p>Discord 채널을 사용하면 Discord 서버의 채널을 파일 저장 위치로 활용할 수 있습니다.</p><h2 id="준비할-것" tabindex="-1">준비할 것 <a class="header-anchor" href="#준비할-것" aria-label="Permalink to &quot;준비할 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>Discord 계정</td><td>서버와 Bot 관리</td></tr><tr><td>Discord 서버</td><td>저장용 채널을 둘 공간</td></tr><tr><td>Discord Bot</td><td>파일 업로드에 사용</td></tr><tr><td>Bot Token</td><td>ImgBed가 Bot을 호출할 때 사용</td></tr><tr><td>채널 ID</td><td>파일을 보낼 Discord 채널 지정</td></tr></tbody></table><h2 id="서버-만들기" tabindex="-1">서버 만들기 <a class="header-anchor" href="#서버-만들기" aria-label="Permalink to &quot;서버 만들기&quot;">​</a></h2><p>저장용 Discord 서버를 만듭니다. 기존 서버를 사용해도 되지만, 운영을 깔끔하게 하려면 전용 서버가 좋습니다.</p><p><img src="'+a+'" alt="서버 만들기" loading="lazy"></p><h2 id="개발자-모드-켜기" tabindex="-1">개발자 모드 켜기 <a class="header-anchor" href="#개발자-모드-켜기" aria-label="Permalink to &quot;개발자 모드 켜기&quot;">​</a></h2><p>채널 ID를 복사하려면 Discord의 개발자 모드를 켭니다.</p><p><img src="'+o+'" alt="개발자 모드" loading="lazy"></p><p>대상 채널을 오른쪽 클릭한 뒤 채널 ID를 복사합니다.</p><p><img src="'+d+'" alt="채널 ID" loading="lazy"></p><h2 id="bot-만들고-token-확인" tabindex="-1">Bot 만들고 Token 확인 <a class="header-anchor" href="#bot-만들고-token-확인" aria-label="Permalink to &quot;Bot 만들고 Token 확인&quot;">​</a></h2><p>Discord Developer Portal에서 애플리케이션을 만들고 Bot을 추가합니다. Bot Token을 복사해 안전하게 보관합니다.</p><p><img src="'+r+'" alt="Bot Token" loading="lazy"></p><h2 id="bot을-서버에-초대하기" tabindex="-1">Bot을 서버에 초대하기 <a class="header-anchor" href="#bot을-서버에-초대하기" aria-label="Permalink to &quot;Bot을 서버에 초대하기&quot;">​</a></h2><p>OAuth2 설정에서 Bot 권한을 선택하고, 생성된 초대 URL로 서버에 Bot을 추가합니다.</p><p><img src="'+e+'" alt="Bot 권한" loading="lazy"></p><p><img src="'+i+'" alt="Bot 초대" loading="lazy"></p><p>Bot에는 대상 채널에서 메시지 보내기와 파일 첨부 권한이 필요합니다.</p><h2 id="imgbed에-입력하기" tabindex="-1">ImgBed에 입력하기 <a class="header-anchor" href="#imgbed에-입력하기" aria-label="Permalink to &quot;ImgBed에 입력하기&quot;">​</a></h2><p>업로드 설정에서 <code>Discord</code>를 선택합니다.</p><table tabindex="0"><thead><tr><th>항목</th><th>입력 내용</th></tr></thead><tbody><tr><td>채널 이름</td><td>예: <code>Discord Storage</code></td></tr><tr><td>Bot Token</td><td>Developer Portal에서 받은 Token</td></tr><tr><td>Channel ID</td><td>파일을 보낼 채널 ID</td></tr><tr><td>메모</td><td>선택 사항</td></tr></tbody></table><p><img src="'+l+'" alt="Discord 설정" loading="lazy"></p><h2 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h2><ol><li>저장 후 Discord 채널 카드가 표시됩니다.</li><li>테스트 이미지를 업로드합니다.</li><li>대상 Discord 채널에 파일이 올라오는지 확인합니다.</li><li>ImgBed가 반환한 링크가 열리는지 확인합니다.</li></ol><p>실패하면 Bot Token, Channel ID, Bot 권한, 서버 초대 상태를 먼저 확인하세요.</p>',27)])])}const q=s(p,[["render",m]]);export{f as __pageData,q as default};
